import pandas as pd

def transform_df(df):
    new_rows = []
    for _, row in df.iterrows():
        for hour in range(1, 11):
            new_row = row.copy()
            new_row['Time since surgery'] = hour
            new_row['Value'] = row[f'Hour {hour}']
            new_rows.append(new_row)
    return pd.DataFrame(new_rows)

